class MagicDictionary:
    def __init__(self):
        self.trie = {}

    def buildDict(self, dictionary: list[str]) -> None:
        for word in dictionary:
            node = self.trie
            for char in word:
                if char not in node:
                    node[char] = {}
                node = node[char]
            node['_end_'] = True

    def search(self, searchWord: str) -> bool:
        def dfs(node: dict, k: int, mismatches: int) -> bool:
            if mismatches > 1:
                return False

            if k == len(searchWord):
                return '_end_' in node and mismatches == 1

            for char_code in range(ord('a'), ord('z') + 1):
                char = chr(char_code)

                if char in node:
                    new_mismatches = mismatches + (1 if char != searchWord[k] else 0)
                    if dfs(node[char], k + 1, new_mismatches):
                        return True

            return False

        return dfs(self.trie, 0, 0)
